71	  predicate: (item: Item) => boolean,
72	  rate: number,
73	): number =>
74	  items
75	    .filter(predicate)
76	    .reduce((total, item) => total + BASE_PREMIUM[item.type] * rate, 0);
77	
78	const perItemSurcharges = (items: Item[]): number =>
