88	const quotePremiumFor = (customer: Customer, { items }: QuoteStep): QuoteResult => {
89	  const policyBase = sumBasePremiumsByGroup(items);
90	  const total =
91	    policyBase
92	    + perItemSurcharges(items)
93	    + policyWideAdjustments(policyBase, customer)
94	    + PROCESSING_FEE;
95	  return { premium: Math.ceil(total) };
