100	const insuranceSumFor = (items: Item[]): number =>
101	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
102	
103	const createPolicy = ({ items }: QuoteStep): Policy => ({
104	  items,
105	  remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER,
106	});
