108	const payoutForDamage = (damage: Damage): number =>
109	  Math.max(0, damage.amount - DEDUCTIBLE);
110	
111	const processClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
112	  const payout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
113	  policy.remainingCap -= payout;
114	  return { payout, remainingCap: policy.remainingCap };
115	};
