const settleClaim = (policy: Policy, { incident }: ClaimStep): { result: ClaimResult; policy: Policy } => {
  const payout = incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
  const remainingCap = policy.remainingCap - payout;
  return { result: { payout, remainingCap }, policy: { ...policy, remainingCap } };
};

type RunState = { results: StepResult[]; policies: Policy[] };

const applyStep = (customer: Customer) => (state: RunState, step: Step): RunState => {
  if (step.op === "quote") {
    return {
      results: [...state.results, quotePremiumFor(customer, step)],
      policies: [...state.policies, createPolicy(step)],
    };
  }
  const { result, policy } = settleClaim(state.policies[step.policy], step);
  return {
    results: [...state.results, result],
    policies: state.policies.map((p, i) => (i === step.policy ? policy : p)),
  };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const { results } = scenario.steps.reduce(
    applyStep(scenario.customer),
    { results: [], policies: [] },
  );
  return { results };
};

