const totalPayout = (damages: Damage[]): number =>
  damages.reduce((sum, d) => sum + payoutForDamage(d), 0);

const settleClaim = (policy: Policy, { incident }: ClaimStep): ClaimResult => {
  const payout = totalPayout(incident.damages);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
  const policies: Policy[] = [];
  const handle = (step: Step): StepResult => {
    if (step.op === "quote") {
      policies.push(createPolicy(step));
      return quotePremiumFor(customer, step);
    }
    return settleClaim(policies[step.policy], step);
  };
  return { results: steps.map(handle) };
};
